// Node.js built-in fs module for file writing
const fs = require('fs');
const path = require('path');

// ── Output directory for Day 2 data ─────────────────────────
const DIR = path.join(__dirname, '..', 'data', 'challenge', 'day-02');

// ── Helper: write JSON file with pretty printing ─────────────
function writeJSON(filename, data) {
  // Build the full file path
  const filePath = path.join(DIR, filename);
  // Convert object to formatted JSON string (2-space indent)
  const jsonStr = JSON.stringify(data, null, 2);
  // Write the file synchronously
  fs.writeFileSync(filePath, jsonStr, 'utf8');
  // Log the file size for verification
  const lines = jsonStr.split('\n').length;
  console.log(`✅ ${filename} — ${lines} lines, ${data.words?.length || data.questions?.length || data.drills?.length || data.tasks?.length || data.exercises?.length || data.passages?.length || data.stories?.length || data.dialogues?.length || data.flashcards?.length || data.entries?.length || data.scenarios?.length || '✓'} items`);
}

